using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
            Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
            Ratings = [5, 4, 5, 4, 5]
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper",
            Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan over medium heat.\n3. Whisk eggs with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale, then remove from heat.\n5. Quickly stir in egg mixture to create a creamy sauce.\n6. Serve immediately with extra cheese and pepper.",
            Ratings = [5, 5, 4]
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nCanned tomatoes\nHeavy cream\nGarlic\nGinger\nOnion",
            Steps = "1. Marinate chicken in yogurt and spices for at least 1 hour.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger in a pot.\n4. Add tomatoes and simmer for 15 minutes.\n5. Stir in cream and cooked chicken.\n6. Simmer for 10 minutes and serve with rice or naan.",
            Ratings = [5, 4, 4, 5]
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
            Ingredients = "Rice noodles\nTofu\nBean sprouts\nCarrots\nGreen onions\nPeanuts\nLime\nFish sauce\nTamarind paste\nBrown sugar",
            Steps = "1. Soak rice noodles in warm water for 20 minutes.\n2. Press and cube tofu, then pan-fry until golden.\n3. Mix tamarind paste, fish sauce, and brown sugar for sauce.\n4. Stir-fry vegetables on high heat for 2 minutes.\n5. Add noodles and sauce, tossing to combine.\n6. Serve topped with peanuts, bean sprouts, and lime wedges.",
            Ratings = [4, 3, 5]
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Ingredients = "Ground beef\nTaco shells\nLettuce\nTomato\nCheddar cheese\nSour cream\nCumin\nChili powder\nGarlic powder\nOnion",
            Steps = "1. Brown ground beef with diced onion.\n2. Add cumin, chili powder, and garlic powder.\n3. Warm taco shells in the oven.\n4. Fill shells with seasoned beef.\n5. Top with shredded lettuce, diced tomato, cheese, and sour cream.",
            Ratings = [4, 4, 5, 3]
        },
        new()
        {
            Id = 6, Title = "Guacamole", Category = "Mexican",
            Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt",
            Steps = "1. Halve avocados and remove pits.\n2. Mash avocado to desired consistency.\n3. Stir in diced onion, tomato, and jalapeño.\n4. Add chopped cilantro and lime juice.\n5. Season with salt and serve with tortilla chips.",
            Ratings = [5, 5, 5, 4, 5]
        },
        new()
        {
            Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts",
            Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
            Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold chocolate mixture into eggs, then add flour.\n5. Pour into greased ramekins.\n6. Bake for 12-14 minutes until edges are set but center is soft.\n7. Invert onto plates and serve immediately.",
            Ratings = [5, 5, 4, 5]
        },
        new()
        {
            Id = 8, Title = "Miso Soup", Category = "Asian",
            Ingredients = "Dashi stock\nMiso paste\nTofu\nWakame seaweed\nGreen onions",
            Steps = "1. Bring dashi stock to a gentle simmer.\n2. Add cubed tofu and wakame.\n3. Remove from heat and dissolve miso paste into broth.\n4. Ladle into bowls and garnish with sliced green onions.",
            Ratings = [4, 4, 3]
        },
    ];

    private int _nextId = 9;

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }

    public void AddRecipe(string title, string category, string ingredients, string steps)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        });
    }
}

