@using RecipeShare.Services

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= DisplayRating ? "filled" : "")"
              @onmouseover="() => _hoverRating = star"
              @onmouseout="() => _hoverRating = 0"
              @onclick="() => SubmitRating(star)"
              role="button"
              title="Rate @star star(s)">
            ★
        </span>
    }
    <span class="rating-text">
        @if (AverageRating > 0)
        {
            <text>@AverageRating / 5 (@TotalRatings ratings)</text>
        }
        else
        {
            <text>No ratings yet</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private int _hoverRating;
    private int _selectedRating;
    private int DisplayRating => _hoverRating > 0 ? _hoverRating : _selectedRating;

    private void SubmitRating(int stars)
    {
        _selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            TotalRatings = recipe.Ratings.Count;
        }
    }
}

