@page "/"
@using RecipeShare.Services

<PageTitle>RecipeShare — Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 RecipeShare</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mt-2">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col">
            <a href="/category/@category" class="text-decoration-none">
                <div class="card h-100 shadow-sm category-card">
                    <div class="card-body text-center">
                        <h3 class="card-title">@GetEmoji(category) @category</h3>
                        <p class="card-text text-muted">
                            @RecipeService.GetByCategory(category).Count recipe(s)
                        </p>
                    </div>
                </div>
            </a>
        </div>
    }
</div>

<div class="text-center mt-5">
    <a href="/submit" class="btn btn-success btn-lg">📝 Submit Your Recipe</a>
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private static string GetEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

arguments.file_text:
@page "/category/{CategoryName}"
@using RecipeShare.Services

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var recipe in Recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">
                            <a href="/recipe/@recipe.Id">@recipe.Title</a>
                        </h4>
                        <p class="card-text text-muted">
                            @if (recipe.AverageRating > 0)
                            {
                                <span>⭐ @recipe.AverageRating / 5 (@recipe.Ratings.Count ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@using RecipeShare.Components.Shared

<PageTitle>@(Recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

