@page "/"
@using RecipeShare.Services

<PageTitle>RecipeShare — Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 RecipeShare</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mt-2">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col">
            <a href="/category/@category" class="text-decoration-none">
                <div class="card h-100 shadow-sm category-card">
                    <div class="card-body text-center">
                        <h3 class="card-title">@GetEmoji(category) @category</h3>
                        <p class="card-text text-muted">
                            @RecipeService.GetByCategory(category).Count recipe(s)
                        </p>
                    </div>
                </div>
            </a>
        </div>
    }
</div>

<div class="text-center mt-5">
    <a href="/submit" class="btn btn-success btn-lg">📝 Submit Your Recipe</a>
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private static string GetEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<h1>📝 Submit a Recipe</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "<strong>@_title</strong>" has been submitted.
        <a href="/">Browse recipes</a>
    </div>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_title" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="_category" class="form-select" required>
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="_ingredients" class="form-control" rows="6" required />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="_steps" class="form-control" rows="6" required />
        </div>

        <button type="submit" class="btn btn-primary btn-lg"
                disabled="@(string.IsNullOrWhiteSpace(_title) || string.IsNullOrWhiteSpace(_category) || string.IsNullOrWhiteSpace(_ingredients) || string.IsNullOrWhiteSpace(_steps))">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private string _title = string.Empty;
    private string _category = string.Empty;
    private string _ingredients = string.Empty;
    private string _steps = string.Empty;
    private bool _submitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_title) || string.IsNullOrWhiteSpace(_category)
            || string.IsNullOrWhiteSpace(_ingredients) || string.IsNullOrWhiteSpace(_steps))
        {
            return;
        }

        RecipeService.AddRecipe(_title, _category, _ingredients, _steps);
        _submitted = true;
    }
}

